  coaching_execution = '{"movement_description":"Perform Low-Level Reactive Agility Box as a short neural-quality exposure. The athlete starts organized, waits for the cue or rhythm, performs the action with clean mechanics, and resets before fatigue changes timing or posture.","setup":["Set cones to mark a short, clear lane or decision area.","Keep distances short enough that every rep can be sharp and controlled.","Demonstrate one slow rep before asking for crisp reps."],"execution_steps":["Athlete holds the start position and waits for the cue instead of guessing.","Coach or partner gives one clear visual or auditory cue.","Athlete makes the correct first movement, finishes the required action, and regains control.","Reset fully before the next rep so attention and mechanics stay crisp."],"coach_cues":["Fast signal, clean answer.","Stay relaxed where you can.","Own the finish.","Push the ground away.","Eyes up, hips under you.","Quiet contacts."],"common_faults":["Rushing before the cue is clear.","Adding volume after timing has degraded.","Standing tall before the first step.","Crossing feet or reaching outside the base unnecessarily.","Landing loud or stiff.","Knees collapsing inward or feet spinning out."],"breathing_cues":["Breathe quietly before the rep.","Do not hold breath to force coordination.","Reset breathing before the next attempt."],"quality_gate":"The athlete reads the cue, performs the correct action, and resets without guessing, rushing, or losing posture. Learning quality is more important than speed.","stop_signs":["Dizziness, nausea, or disorientation.","Pain, limping, or protective movement.","Timing gets slower or noticeably less coordinated.","Contacts get loud, uncontrolled, or asymmetrical."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Acceleration work","Jump or landing work","Strength training","Sport-skill practice"],"pairs_well_after":["General temperature raise","Dynamic mobility","Low-level activation"],"good_for_sessions":["general_warmup","deceleration"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Active calf, Achilles, knee, or hip irritation","Slippery surface or unsafe stopping area"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal demo: front and side view","Motor learning: low-fatigue, high-quality practice","Sprint, plyometric, and landing progression principles as appropriate"],"internal_notes":["Neural emphasis: quality over quantity.","Use short exposures before the main training stress, not as metabolic finishers.","Normalize taxonomy keys to exercise_card_details_for_llm.md before import."]}'::jsonb,
  updated_at = now()
WHERE slug = 'low-level-reactive-agility-box';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'perception_action_skill',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = TRUE,
  fatigue_sensitivity = 4,
  fatigue_cost = 3,
  technical_complexity = 3,
  impact_level = 1,
  intensity_ceiling = 'moderate',
  notes = ''
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'movement_intelligence'
JOIN coaching.phase_order_slot pos ON pos.key = 'perception_action_skill' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'low-level-reactive-agility-box';

UPDATE coaching.exercise_dosage_profile d SET
  volume_unit = 'attempts',
  default_sets = 2,
  default_reps = 3,
  default_distance = NULL,
  default_work_seconds = 15,
  default_rest_seconds = 60,
  est_seconds_per_set = 75,
  default_rpe_min = 3,
  default_rpe_max = 6,
  session_volume_min = NULL,
  session_volume_max = NULL
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'low-level-reactive-agility-box';

UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = TRUE,
  weekly_max_frequency = 6,
  minimum_hours_between_hard_exposures = 0,
  counts_as_high_intensity = FALSE,
  counts_as_high_impact = FALSE,
  counts_as_neural = TRUE,
  counts_as_tissue_stress = FALSE,
  counts_as_conditioning = FALSE
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'low-level-reactive-agility-box';

UPDATE coaching.exercise_safety_profile s SET
  risk_level = 2,
  impact_level = 1,
  requires_spotting = FALSE,
  requires_coach_supervision = 'recommended',
  readiness_checks = ARRAY['Athlete can hold the start or landing posture without pain.', 'Breathing stays controlled and the athlete can follow cues.', 'Movement quality stays sharp at the planned speed.']::text[],
  contraindications = ARRAY['Active calf, Achilles, knee, or hip irritation', 'Slippery surface or unsafe stopping area']::text[],
  common_substitutions = ARRAY['Snap-Down to Athletic Stick', 'Low-amplitude pogo', 'March or step-to-stick alternative']::text[]
FROM coaching.exercise e
WHERE s.exercise_id = e.id AND e.slug = 'low-level-reactive-agility-box';

